class BaseGbart:
    def time_gbart(self, *_: Any) -> None:
        """Time instantiating the class."""
        with redirect_stdout(StringIO()):
            if self.predict:
                ypred = self.bart.predict(self.test.x.T if X_N_BY_P else self.test.x)
                block_until_ready(ypred)
            else:
